using Auth0.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authentication.OpenIdConnect;
using Microsoft.EntityFrameworkCore;
using MyBlog.Domain.Interfaces;
using MyBlog.Web.Components;
using MyBlog.Web.Data;
using System.Security.Claims;
using System.Text.Json;

var builder = WebApplication.CreateBuilder(args);

builder.AddServiceDefaults();

// Razor + Blazor Server
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

// Auth0 authentication
var auth0Domain = builder.Configuration["Auth0:Domain"];
var auth0ClientId = builder.Configuration["Auth0:ClientId"];

if (string.IsNullOrEmpty(auth0Domain) || string.IsNullOrEmpty(auth0ClientId))
{
    throw new InvalidOperationException(
        "Auth0 configuration is missing or incomplete. Set these user secrets for the Web project:\n" +
        "  dotnet user-secrets set \"Auth0:Domain\" \"<your-tenant>.auth0.com\" --project src/Web\n" +
        "  dotnet user-secrets set \"Auth0:ClientId\" \"<your-client-id>\" --project src/Web\n" +
        "  dotnet user-secrets set \"Auth0:ClientSecret\" \"<your-client-secret>\" --project src/Web");
}

var auth0RoleClaimTypes = builder.Configuration.GetSection("Auth0:RoleClaimTypes").Get<string[]>() ??
[
    "https://myblog/roles",
    "roles",
    "role"
];

IReadOnlyList<string> expandRoleValues(string claimValue)
{
    if (string.IsNullOrWhiteSpace(claimValue))
    {
        return [];
    }

    var trimmed = claimValue.Trim();

    if (trimmed.StartsWith("[", StringComparison.Ordinal))
    {
        try
        {
            using var document = JsonDocument.Parse(trimmed);

            if (document.RootElement.ValueKind == JsonValueKind.Array)
            {
                var roles = new List<string>();

                foreach (var element in document.RootElement.EnumerateArray())
                {
                    var role = element.GetString();

                    if (!string.IsNullOrWhiteSpace(role))
                    {
                        roles.Add(role);
                    }
                }

                return roles;
            }
        }
        catch (JsonException)
        {
        }
    }

    if (trimmed.Contains(',', StringComparison.Ordinal))
    {
        return trimmed.Split(',', StringSplitOptions.TrimEntries | StringSplitOptions.RemoveEmptyEntries);
    }

    return [trimmed];
}

builder.Services.AddAuth0WebAppAuthentication(opts =>
{
    opts.Domain = auth0Domain;
    opts.ClientId = auth0ClientId;
    opts.ClientSecret = builder.Configuration["Auth0:ClientSecret"];
    opts.CallbackPath = "/signin-auth0";
});

builder.Services.PostConfigure<OpenIdConnectOptions>(Auth0Constants.AuthenticationScheme, options =>
{
    options.TokenValidationParameters.RoleClaimType = ClaimTypes.Role;

    var existingOnTokenValidated = options.Events.OnTokenValidated;
    options.Events.OnTokenValidated = async context =>
    {
        await existingOnTokenValidated(context);

        if (context.Principal?.Identity is not ClaimsIdentity identity)
        {
            return;
        }

        foreach (var roleClaimType in auth0RoleClaimTypes)
        {
            foreach (var claim in identity.FindAll(roleClaimType).ToList())
            {
                foreach (var role in expandRoleValues(claim.Value))
                {
                    if (!identity.HasClaim(ClaimTypes.Role, role))
                    {
                        identity.AddClaim(new System.Security.Claims.Claim(ClaimTypes.Role, role));
                    }
                }
            }
        }
    };
});

builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthorization();

// MongoDB (Aspire-managed connection "myblog")
builder.AddMongoDBClient("myblog");
builder.Services.AddDbContextFactory<BlogDbContext>((sp, options) =>
{
    var mongoClient = sp.GetRequiredService<MongoDB.Driver.IMongoClient>();
    options.UseMongoDB(mongoClient, "myblog");
});

// Redis distributed cache (Aspire-managed connection "redis")
builder.AddRedisDistributedCache("redis");

// Local in-memory cache (L1)
builder.Services.AddMemoryCache();

// Repository: concrete + interface
builder.Services.AddScoped<MongoDbBlogPostRepository>();
builder.Services.AddScoped<IBlogPostRepository>(sp =>
    sp.GetRequiredService<MongoDbBlogPostRepository>());

// MediatR — scans Web assembly for all handlers
builder.Services.AddMediatR(cfg =>
    cfg.RegisterServicesFromAssembly(typeof(Program).Assembly));

// HttpClient for Auth0 Management API
builder.Services.AddHttpClient();

var app = builder.Build();

// Configure the HTTP request pipeline
if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
    app.UseHsts();
}

app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseHttpsRedirection();

app.UseAuthentication();
app.UseAuthorization();
app.UseAntiforgery();

app.MapStaticAssets();

// Auth0 login/logout endpoints
app.MapGet("/Account/Login", async (HttpContext ctx, string? returnUrl) =>
{
    var props = new LoginAuthenticationPropertiesBuilder()
        .WithRedirectUri(returnUrl ?? "/")
        .Build();
    await ctx.ChallengeAsync(Auth0Constants.AuthenticationScheme, props);
}).AllowAnonymous();

app.MapGet("/Account/Logout", async ctx =>
{
    var props = new LogoutAuthenticationPropertiesBuilder()
        .WithRedirectUri("/")
        .Build();
    await ctx.SignOutAsync(Auth0Constants.AuthenticationScheme, props);
    await ctx.SignOutAsync();
}).RequireAuthorization();

app.MapRazorComponents<App>()
    .AddInteractiveServerRenderMode();

app.MapDefaultEndpoints();
app.Run();

using Auth0.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authentication.OpenIdConnect;
using Microsoft.EntityFrameworkCore;
using MyBlog.Domain.Interfaces;
using MyBlog.Web.Components;
using MyBlog.Web.Data;
using MyBlog.Web.Security;
using System.Security.Claims;

var builder = WebApplication.CreateBuilder(args);

builder.AddServiceDefaults();

// Razor + Blazor Server
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

// Auth0 authentication
var auth0Domain = builder.Configuration["Auth0:Domain"];
var auth0ClientId = builder.Configuration["Auth0:ClientId"];

if (string.IsNullOrEmpty(auth0Domain) || string.IsNullOrEmpty(auth0ClientId))
{
    throw new InvalidOperationException(
        "Auth0 configuration is missing or incomplete. Set these user secrets for the Web project:\n" +
        "  dotnet user-secrets set \"Auth0:Domain\" \"<your-tenant>.auth0.com\" --project src/Web\n" +
        "  dotnet user-secrets set \"Auth0:ClientId\" \"<your-client-id>\" --project src/Web\n" +
        "  dotnet user-secrets set \"Auth0:ClientSecret\" \"<your-client-secret>\" --project src/Web");
}

var auth0RoleClaimTypes = RoleClaimsHelper.GetRoleClaimTypes(builder.Configuration);

builder.Services.AddAuth0WebAppAuthentication(opts =>
{
    opts.Domain = auth0Domain;
    opts.ClientId = auth0ClientId;
    opts.ClientSecret = builder.Configuration["Auth0:ClientSecret"];
    opts.CallbackPath = "/signin-auth0";
});

builder.Services.PostConfigure<OpenIdConnectOptions>(Auth0Constants.AuthenticationScheme, options =>
{
    options.TokenValidationParameters.RoleClaimType = ClaimTypes.Role;

    var existingOnTokenValidated = options.Events.OnTokenValidated;
    options.Events.OnTokenValidated = async context =>
    {
        await existingOnTokenValidated(context);

        if (context.Principal?.Identity is not ClaimsIdentity identity)
        {
            return;
        }

        RoleClaimsHelper.AddRoleClaims(identity, auth0RoleClaimTypes);
    };
});

builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthorization();

// MongoDB (Aspire-managed connection "myblog")
builder.AddMongoDBClient("myblog");
builder.Services.AddDbContextFactory<BlogDbContext>((sp, options) =>
{
    var mongoClient = sp.GetRequiredService<MongoDB.Driver.IMongoClient>();
    options.UseMongoDB(mongoClient, "myblog");
});

// Redis distributed cache (Aspire-managed connection "redis")
builder.AddRedisDistributedCache("redis");

// Local in-memory cache (L1)
builder.Services.AddMemoryCache();

// Repository: concrete + interface
builder.Services.AddScoped<MongoDbBlogPostRepository>();
builder.Services.AddScoped<IBlogPostRepository>(sp =>
    sp.GetRequiredService<MongoDbBlogPostRepository>());

// MediatR — scans Web assembly for all handlers
builder.Services.AddMediatR(cfg =>
    cfg.RegisterServicesFromAssembly(typeof(Program).Assembly));

// HttpClient for Auth0 Management API
builder.Services.AddHttpClient();

var app = builder.Build();

// Configure the HTTP request pipeline
if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
    app.UseHsts();
}

app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseHttpsRedirection();

app.UseAuthentication();
app.UseAuthorization();
app.UseAntiforgery();

app.MapStaticAssets();

// Auth0 login/logout endpoints
app.MapGet("/Account/Login", async (HttpContext ctx, string? returnUrl) =>
{
    var props = new LoginAuthenticationPropertiesBuilder()
        .WithRedirectUri(returnUrl ?? "/")
        .Build();
    await ctx.ChallengeAsync(Auth0Constants.AuthenticationScheme, props);
}).AllowAnonymous();

app.MapGet("/Account/Logout", async ctx =>
{
    var props = new LogoutAuthenticationPropertiesBuilder()
        .WithRedirectUri("/")
        .Build();
    await ctx.SignOutAsync(Auth0Constants.AuthenticationScheme, props);
    await ctx.SignOutAsync();
}).RequireAuthorization();

app.MapRazorComponents<App>()
    .AddInteractiveServerRenderMode();

app.MapDefaultEndpoints();
app.Run();

using System.Security.Claims;
using System.Text.Json;

namespace MyBlog.Web.Security;

public static class RoleClaimsHelper
{
    public static readonly string[] DefaultRoleClaimTypes =
    [
        "https://myblog/roles",
        "roles",
        "role"
    ];

    public static IReadOnlyList<string> GetRoleClaimTypes(IConfiguration configuration)
    {
        var configured = configuration.GetSection("Auth0:RoleClaimTypes").Get<string[]>();

        return configured is { Length: > 0 }
            ? configured.Where(value => !string.IsNullOrWhiteSpace(value))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToArray()
            : DefaultRoleClaimTypes;
    }

    public static IReadOnlyList<string> ExpandRoleValues(string? claimValue)
    {
        if (string.IsNullOrWhiteSpace(claimValue))
        {
            return [];
        }

        var trimmed = claimValue.Trim();

        if (trimmed.StartsWith("[", StringComparison.Ordinal))
        {
            try
            {
                using var document = JsonDocument.Parse(trimmed);

                if (document.RootElement.ValueKind == JsonValueKind.Array)
                {
                    return document.RootElement
                        .EnumerateArray()
                        .Select(element => element.GetString())
                        .Where(role => !string.IsNullOrWhiteSpace(role))
                        .Cast<string>()
                        .ToArray();
                }
            }
            catch (JsonException)
            {
            }
        }

        if (trimmed.Contains(',', StringComparison.Ordinal))
        {
            return trimmed.Split(',', StringSplitOptions.TrimEntries | StringSplitOptions.RemoveEmptyEntries);
        }

        return [trimmed];
    }

    public static void AddRoleClaims(ClaimsIdentity identity, IEnumerable<string> roleClaimTypes)
    {
        foreach (var roleClaimType in roleClaimTypes)
        {
            foreach (var claim in identity.FindAll(roleClaimType).ToList())
            {
                foreach (var role in ExpandRoleValues(claim.Value))
                {
                    if (!identity.HasClaim(ClaimTypes.Role, role))
                    {
                        identity.AddClaim(new Claim(ClaimTypes.Role, role));
                    }
                }
            }
        }
    }

    public static IReadOnlyList<string> GetRoles(ClaimsPrincipal user, IEnumerable<string>? roleClaimTypes = null)
    {
        var types = (roleClaimTypes ?? DefaultRoleClaimTypes.Append(ClaimTypes.Role))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .ToArray();

        return user.Claims
            .Where(claim => types.Contains(claim.Type, StringComparer.OrdinalIgnoreCase))
            .SelectMany(claim => ExpandRoleValues(claim.Value))
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(role => role)
            .ToList();
    }
}

using System.Security.Claims;
using Bunit;
using FluentAssertions;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components;
using Microsoft.Extensions.DependencyInjection;
using MyBlog.Web.Components.Layout;
using MyBlog.Unit.Tests.Testing;

namespace MyBlog.Unit.Tests.Components.Layout;

public class NavMenuTests : BunitContext
{
    public NavMenuTests()
    {
        Services.AddAuthorizationCore();
        Services.AddSingleton<IAuthorizationService, TestAuthorizationService>();
    }

    [Fact]
    public void UnauthenticatedUser_SeesLoginAndNoProtectedLinks()
    {
        var cut = RenderForUser(CreatePrincipal(authenticated: false));

        cut.Markup.Should().Contain("Login");
        cut.Markup.Should().NotContain("Logout");
        cut.Markup.Should().NotContain("Manage Users");
        cut.Markup.Should().NotContain("New Post");
    }

    [Fact]
    public void AuthenticatedAdmin_UsesDisplayNameAsProfileLabel_AndShowsAdminLinks()
    {
        var cut = RenderForUser(CreatePrincipal(name: "Admin User", roles: ["Admin"]));

        cut.Markup.Should().Contain("Admin User");
        cut.Markup.Should().Contain("Manage Users");
        cut.Markup.Should().Contain("New Post");
        cut.Markup.Should().Contain("Logout");
        cut.Markup.Should().NotContain("Logout (Admin User)");
    }

    [Fact]
    public void AuthenticatedUser_WithoutName_FallsBackToProfileLabel()
    {
        var cut = RenderForUser(CreatePrincipal(roles: ["Author"]));

        cut.Markup.Should().Contain(">Profile<");
        cut.Markup.Should().Contain("New Post");
        cut.Markup.Should().NotContain("Manage Users");
    }

    [Fact]
    public void NavMenu_LoadsThemeFromJs_AndAllowsThemeInteraction()
    {
        JSInterop.Mode = JSRuntimeMode.Loose;
        JSInterop.Setup<string>("themeManager.getColor").SetResult("green");
        JSInterop.Setup<string>("themeManager.getBrightness").SetResult("dark");

        var cut = RenderForUser(CreatePrincipal(name: "Theme User", roles: ["Admin"]));

        cut.WaitForAssertion(() => cut.Markup.Should().Contain("Theme User"));
        cut.Find("select").Change("yellow");
        cut.FindAll("button").Last().Click();

        JSInterop.Invocations.Should().Contain(invocation => invocation.Identifier == "themeManager.getColor");
        JSInterop.Invocations.Should().Contain(invocation => invocation.Identifier == "themeManager.getBrightness");
        JSInterop.Invocations.Should().Contain(invocation => invocation.Identifier == "themeManager.setColor");
        JSInterop.Invocations.Should().Contain(invocation => invocation.Identifier == "themeManager.setBrightness");
    }

    private IRenderedComponent<NavMenu> RenderForUser(ClaimsPrincipal principal)
    {
        return Render<NavMenu>(parameters => parameters
            .AddCascadingValue(Task.FromResult(new AuthenticationState(principal))));
    }

    private static ClaimsPrincipal CreatePrincipal(bool authenticated = true, string? name = null, string[]? roles = null)
    {
        if (!authenticated)
        {
            return new ClaimsPrincipal(new ClaimsIdentity());
        }

        var claims = new List<Claim>();

        if (!string.IsNullOrWhiteSpace(name))
        {
            claims.Add(new Claim(ClaimTypes.Name, name));
        }

        if (roles is not null)
        {
            claims.AddRange(roles.Select(role => new Claim(ClaimTypes.Role, role)));
        }

        return new ClaimsPrincipal(new ClaimsIdentity(claims, "TestAuth", ClaimTypes.Name, ClaimTypes.Role));
    }
}

