            .Returns(
                Task.FromResult(Result.Ok<IReadOnlyList<UserWithRolesDto>>(users)),
                Task.FromResult(Result.Ok<IReadOnlyList<UserWithRolesDto>>(refreshedUsers)));
        sender.Send(Arg.Any<GetAvailableRolesQuery>(), Arg.Any<CancellationToken>())
            .Returns(Task.FromResult(Result.Ok<IReadOnlyList<RoleDto>>(roles)));
        sender.Send(Arg.Any<RemoveRoleCommand>(), Arg.Any<CancellationToken>())
            .Returns(Task.FromResult(Result.Ok()));

        Services.AddSingleton(sender);

        var cut = RenderWithUser<ManageRoles>(CreatePrincipal("Admin User", ["Admin"]));

        cut.FindAll("button").First(button => button.TextContent.Contains("- Author")).Click();

        sender.Received(1).Send(Arg.Is<RemoveRoleCommand>(command => command.UserId == "user-1" && command.RoleId == "role-author"), Arg.Any<CancellationToken>());
        cut.WaitForAssertion(() =>
        {
            cut.Markup.Should().Contain("+ Author");
            cut.Markup.Should().Contain("<td class=\"px-4 py-3\">Admin</td>");
        });
    }

    private IRenderedComponent<TComponent> RenderWithUser<TComponent>(
        ClaimsPrincipal principal,
        Action<ComponentParameterCollectionBuilder<TComponent>>? configure = null)
        where TComponent : IComponent
    {
        return Render<TComponent>(parameters =>
        {
            parameters.AddCascadingValue(Task.FromResult(new AuthenticationState(principal)));
            configure?.Invoke(parameters);
        });
    }

    private static ClaimsPrincipal CreatePrincipal(string name, string[] roles)
    {
        var claims = new List<Claim> { new(ClaimTypes.Name, name) };
        claims.AddRange(roles.Select(role => new Claim(ClaimTypes.Role, role)));
        return new ClaimsPrincipal(new ClaimsIdentity(claims, "TestAuth", ClaimTypes.Name, ClaimTypes.Role));
    }
}

using System.Security.Claims;
using Bunit;
using FluentAssertions;
using Microsoft.AspNetCore.Components.Authorization;
using MyBlog.Web.Features.UserManagement;

namespace MyBlog.Unit.Tests.Features.UserManagement;

public class ProfileTests : BunitContext
{
    [Fact]
    public void Profile_RendersIdentityDetailsRolesPictureAndClaims()
    {
        var principal = CreatePrincipal(
            name: "Admin User",
            email: "admin@example.com",
            userId: "auth0|123",
            pictureUrl: "https://example.com/avatar.png",
            rolesJson: "[\"Admin\",\"Author\"]",
            extraClaims: [new Claim("department", "Engineering")]);

        var cut = RenderForUser(principal);

        cut.Markup.Should().Contain("Admin User");
        cut.Markup.Should().Contain("admin@example.com");
        cut.Markup.Should().Contain("auth0|123");
        cut.Markup.Should().Contain("avatar.png");
        cut.Markup.Should().Contain("Admin");
        cut.Markup.Should().Contain("Author");
        cut.Markup.Should().Contain("department");
        cut.Markup.Should().Contain("Engineering");
    }

    [Fact]
    public void Profile_UsesFallbackValues_WhenOptionalClaimsAreMissing()
    {
        var principal = CreatePrincipal(
            name: null,
            email: null,
            userId: null,
            pictureUrl: null,
            rolesJson: null,
            extraClaims: []);

        var cut = RenderForUser(principal);

        cut.Markup.Should().Contain("Unknown User");
        cut.Markup.Should().Contain("No email claim found");
        cut.Markup.Should().Contain("No roles found in the current claims.");
        cut.Markup.Should().Contain(">NE<");
    }

    private IRenderedComponent<Profile> RenderForUser(ClaimsPrincipal principal)
    {
        return Render<Profile>(parameters => parameters
            .AddCascadingValue(Task.FromResult(new AuthenticationState(principal))));
    }

    private static ClaimsPrincipal CreatePrincipal(
        string? name,
        string? email,
        string? userId,
        string? pictureUrl,
        string? rolesJson,
        IEnumerable<Claim> extraClaims)
    {
        var claims = new List<Claim>();

        if (!string.IsNullOrWhiteSpace(name))
        {
            claims.Add(new Claim(ClaimTypes.Name, name));
        }

        if (!string.IsNullOrWhiteSpace(email))
        {
            claims.Add(new Claim(ClaimTypes.Email, email));
        }

        if (!string.IsNullOrWhiteSpace(userId))
        {
            claims.Add(new Claim(ClaimTypes.NameIdentifier, userId));
        }

        if (!string.IsNullOrWhiteSpace(pictureUrl))
        {
            claims.Add(new Claim("picture", pictureUrl));
        }

        if (!string.IsNullOrWhiteSpace(rolesJson))
        {
            claims.Add(new Claim("https://myblog/roles", rolesJson));
        }

        claims.AddRange(extraClaims);

        return new ClaimsPrincipal(new ClaimsIdentity(claims, "TestAuth", ClaimTypes.Name, ClaimTypes.Role));
    }
}

using Domain.Abstractions;
using FluentAssertions;

namespace MyBlog.Unit.Tests;

public class ResultTests
{
    [Fact]
    public void Ok_CreatesSuccessfulNonGenericResult()
    {
        var result = Result.Ok();

        result.Success.Should().BeTrue();
        result.Failure.Should().BeFalse();
        result.Error.Should().BeNull();
        result.ErrorCode.Should().Be(ResultErrorCode.None);
    }

    [Fact]
    public void Fail_CreatesFailedNonGenericResultWithCodeAndDetails()
    {
        var result = Result.Fail("boom", ResultErrorCode.Validation, new { Field = "Title" });

        result.Success.Should().BeFalse();
        result.Failure.Should().BeTrue();
        result.Error.Should().Be("boom");
        result.ErrorCode.Should().Be(ResultErrorCode.Validation);
        result.Details.Should().NotBeNull();
    }

    [Fact]
    public void GenericOk_CarriesValue()
    {
        var result = Result.Ok("hello");

        result.Success.Should().BeTrue();
        result.Value.Should().Be("hello");
    }

    [Fact]
    public void GenericFail_CreatesFailedResultWithCode()
    {
        var result = Result.Fail<string>("missing", ResultErrorCode.NotFound);

        result.Success.Should().BeFalse();
        result.Error.Should().Be("missing");
        result.ErrorCode.Should().Be(ResultErrorCode.NotFound);
        result.Value.Should().BeNull();
    }

    [Fact]
    public void FromValue_ReturnsFailedResultWhenValueIsNull()
    {
        string? value = null;

        var result = Result.FromValue(value);

        result.Success.Should().BeFalse();
        result.Error.Should().Be("Provided value is null.");
    }

    [Fact]
    public void ImplicitConversions_WorkForGenericResult()
    {
        Result<string> result = "hello";
        string? value = result;

        value.Should().Be("hello");
        result.Value.Should().Be("hello");
    }
}

using System.Security.Claims;
using FluentAssertions;
using Microsoft.Extensions.Configuration;
using MyBlog.Web.Security;

namespace MyBlog.Unit.Tests.Security;

public class RoleClaimsHelperTests
{
    [Fact]
    public void GetRoleClaimTypes_UsesConfiguredDistinctValues_WhenPresent()
    {
        var configuration = new ConfigurationBuilder()
            .AddInMemoryCollection(new Dictionary<string, string?>
            {
                ["Auth0:RoleClaimTypes:0"] = "roles",
                ["Auth0:RoleClaimTypes:1"] = "https://myblog/roles",
                ["Auth0:RoleClaimTypes:2"] = "roles"
            })
            .Build();

        var result = RoleClaimsHelper.GetRoleClaimTypes(configuration);

        result.Should().BeEquivalentTo(["roles", "https://myblog/roles"]);
    }

    [Fact]
    public void GetRoleClaimTypes_ReturnsDefaults_WhenConfigurationIsMissing()
    {
        var configuration = new ConfigurationBuilder().Build();

        var result = RoleClaimsHelper.GetRoleClaimTypes(configuration);

        result.Should().BeEquivalentTo(RoleClaimsHelper.DefaultRoleClaimTypes);
    }

    [Theory]
    [InlineData("Admin", new[] { "Admin" })]
    [InlineData("Admin,Author", new[] { "Admin", "Author" })]
    [InlineData(" [\"Admin\",\"Author\"] ", new[] { "Admin", "Author" })]
    public void ExpandRoleValues_ParsesSupportedFormats(string input, string[] expected)
    {
        var result = RoleClaimsHelper.ExpandRoleValues(input);

        result.Should().BeEquivalentTo(expected);
    }

    [Fact]
    public void AddRoleClaims_AddsExpandedRoleClaimsWithoutDuplicates()
    {
        var identity = new ClaimsIdentity(new[]
        {
            new Claim("roles", "Admin,Author"),
            new Claim(ClaimTypes.Role, "Admin")
        }, "TestAuth", ClaimTypes.Name, ClaimTypes.Role);

        RoleClaimsHelper.AddRoleClaims(identity, ["roles"]);

        identity.FindAll(ClaimTypes.Role)
            .Select(claim => claim.Value)
            .Should()
            .BeEquivalentTo(["Admin", "Author"]);
    }

    [Fact]
    public void GetRoles_CollectsDistinctRolesAcrossMultipleClaimTypes()
    {
        var principal = new ClaimsPrincipal(new ClaimsIdentity(new[]
        {
            new Claim(ClaimTypes.Role, "Admin"),
            new Claim("https://myblog/roles", "[\"Author\",\"Admin\"]"),
            new Claim("roles", "Editor,Author")
        }, "TestAuth", ClaimTypes.Name, ClaimTypes.Role));

        var result = RoleClaimsHelper.GetRoles(principal);

        result.Should().Equal("Admin", "Author", "Editor");
    }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Authorization.Infrastructure;

namespace MyBlog.Unit.Tests.Testing;

internal sealed class TestAuthorizationService : IAuthorizationService
{
    public Task<AuthorizationResult> AuthorizeAsync(ClaimsPrincipal user, object? resource, IEnumerable<IAuthorizationRequirement> requirements)
    {
        foreach (var requirement in requirements)
        {
            switch (requirement)
            {
                case DenyAnonymousAuthorizationRequirement:
                    if (user.Identity?.IsAuthenticated != true)
                    {
                        return Task.FromResult(AuthorizationResult.Failed());
                    }
                    break;

                case RolesAuthorizationRequirement rolesRequirement:
                    if (!rolesRequirement.AllowedRoles.Any(user.IsInRole))
                    {
                        return Task.FromResult(AuthorizationResult.Failed());
                    }
                    break;
            }
        }

        return Task.FromResult(AuthorizationResult.Success());
    }

    public Task<AuthorizationResult> AuthorizeAsync(ClaimsPrincipal user, object? resource, string policyName)
    {
        return Task.FromResult(user.Identity?.IsAuthenticated == true
            ? AuthorizationResult.Success()
            : AuthorizationResult.Failed());
    }
}
